proof fn phi_1_implies_apply_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        p.implies(q).satisfied_by(ex),
        p.satisfied_by(ex),
    ensures
        q.satisfied_by(ex),
{
    implies_apply::<int>(ex, p, q);
}

proof fn phi_3_vacuous_leads_to_requires_equality(spec: TempPred<int>, p: TempPred<int>, q: TempPred<int>, r: TempPred<int>, ex: Execution<int>)
    requires
        spec.entails(always(r)),
        p.and(r) == false_pred::<int>(),
        spec.satisfied_by(ex),
    ensures
        p.leads_to(q).satisfied_by(ex),
{
    vacuous_leads_to::<int>(spec, p, q, r);
}

proof fn phi_5_any_leads_to_from_false_antecedent(spec: TempPred<int>, q: TempPred<int>)
    requires
        spec.entails(always(true_pred::<int>())),
        false_pred::<int>().and(true_pred::<int>()) == false_pred::<int>(),
    ensures
        spec.entails(false_pred::<int>().leads_to(q)),
{
    vacuous_leads_to::<int>(spec, false_pred::<int>(), q, true_pred::<int>());
}
